  ('heelevel3-852a6306-moex-00009', 'heelevel3-852a6306', 'heelevel3-852a6306-moex-114-d174561e', 'sub-heelevel3-852a6306-02', NULL, 'essay', '臺灣在 1993 年成為高齡化社會，2018 年轉為高齡社會，2025 年邁入
超高齡社會，近十多年臺灣民眾的健康狀況已有顯著進步，112年國人
平均餘命為 80.2 歲，其中男性 76.9 歲、女性83.7歲，但是縣市間仍明
顯存在差異。（每小題 10分，共 20 分）
請說明「平均餘命」的定義與「健康平均餘命」的概念。
臺灣的健康差距持續存在，請說明消除健康不平等之行動建議。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:19+00:00", "source_pdf_sha1": "7a2402f767f4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "291", "s": "2012", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法、衛生行政及其相關法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公職護理師"}'::jsonb, NULL),
